            aOrbiterK = ((aOrbiterK ^ aOrbiterG) ^ 12136920812354520974U) ^ aNonceWordI;
            aOrbiterK = RotL64((aOrbiterK * 5391165369852558967U), 43U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterB) + 2465749326638122062U;
            aOrbiterF = (aOrbiterF ^ aOrbiterD) ^ 5686447774167200418U;
            aOrbiterF = RotL64((aOrbiterF * 10499032653444817379U), 13U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterH) + 2950959457371910938U) + aNonceWordD;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterF) ^ 11206701157390959787U;
            aOrbiterJ = RotL64((aOrbiterJ * 3752746998231887587U), 35U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterK) + 3713470190782485353U;
