            aOrbiterE = RotL64((aOrbiterE * 4513581141599085585U), 53U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterG) + 17923384899709645981U;
            aOrbiterI = ((aOrbiterI ^ aOrbiterA) ^ 3541210697958231248U) ^ aOrbiterUpdateSaltA[((aIndex + 19U)) & S_SALT1];
