            //
            aOrbiterB = ((aOrbiterB + aOrbiterI) + 6574055916966150773U) + aOrbiterUpdateSaltB[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterB) ^ 5093058321584100023U;
            aOrbiterH = RotL64((aOrbiterH * 17552596578326993627U), 29U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterC) + 9806220332857515162U;
