            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererH = aWandererH ^ (((RotL64(aIngress, 39U) + RotL64(aOrbiterC, 47U)) + aOrbiterG) + aWandererUpdateSaltF[(((31U - aIndex) + 27U)) & S_SALT1]);
            aWandererA = aWandererA + ((((RotL64(aCross, 5U) + RotL64(aOrbiterE, 37U)) + aOrbiterD) + RotL64(aCarry, 43U)) + aNonceWordK);
