            aOrbiterK = (aOrbiterK + aOrbiterF) + 4507240299805423072U;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 3406253023972327229U;
            aOrbiterG = RotL64((aOrbiterG * 8872946503927900683U), 51U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterK) + 3969817006706981553U;
            aOrbiterI = (((aOrbiterI ^ aOrbiterB) ^ 11828269394303508580U) ^ aOrbiterUpdateSaltE[(((31U - aIndex) + 20U)) & S_SALT1]) ^ aNonceWordL;
            aOrbiterI = RotL64((aOrbiterI * 10855222383869241737U), 35U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterE) + 14557592209796504939U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 3997135344521906404U;
            aOrbiterJ = RotL64((aOrbiterJ * 14511459013770809769U), 19U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 18154435131999538449U;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 10160548485967145221U;
            aOrbiterF = RotL64((aOrbiterF * 15695360100176236587U), 57U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterI) + 4806837965989686902U;
