            //
            aOrbiterE = ((aOrbiterE + aOrbiterH) + 16604936159878953124U) + aOrbiterUpdateSaltF[((aIndex + 6U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterE) ^ 12312523537942929248U;
            aOrbiterC = RotL64((aOrbiterC * 16613494124898320717U), 43U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterG) + 6147327293560634423U) + aOrbiterUpdateSaltC[(((31U - aIndex) + 11U)) & S_SALT1];
